.scroll-track { min-height: 500vh; position: relative; }
.sticky-stage { position: sticky; top: 0; height: 100vh;
  overflow: hidden; background: #000; }
.card { position: absolute; inset: 0; will-change: clip-path; }
.card img { width: 100%; height: 100%; object-fit: cover; display: block; }

var cards = document.querySelectorAll(".card"), N = cards.length;

var ZERO = "polygon(0px 0px,0px 0px,0px 0px)";
function polyUp(c,w,h,amp,waves,zig){
  if(c<=0) return ZERO; if(c>=1) return "inset(0)";
  var A=amp, base=(1-c)*(h+2*A)-A, s=28, pts=[];
  for(var i=0;i<=s;i++){
    var x=w*i/s, ph=i/s*waves*Math.PI*2, sn=Math.sin(ph);
    var v=zig?(2/Math.PI)*Math.asin(sn):sn;
    pts.push(x.toFixed(1)+"px "+(base+A*v).toFixed(1)+"px");
  }
  pts.push(w+"px "+h+"px"); pts.push("0px "+h+"px");
  return "polygon("+pts.join(",")+")";
}

function clipFor(c, w, h){ return polyUp(c,w,h,42,2.5,false); }

// 스크롤 진행률 p(0~1) → 세그먼트 + 로컬 진행률 → 다음 이미지 물결 reveal
function applyReveal(p){
  var w = innerWidth, h = innerHeight, segs = N - 1;
  var fp = p * segs, idx = Math.min(Math.floor(fp), segs - 1), local = fp - idx;
  cards.forEach(function(c, i){
    var cov = i === 0 ? 1 : i <= idx ? 1 : i === idx + 1 ? local : 0;
    c.style.zIndex = i;
    c.style.clipPath = clipFor(cov, w, h);
  });
}

